TeachEvent = TeachEvent or {className = "TeachEvent"}
local self = TeachEvent

TeachEvent.bEnabled = true
TeachEvent.bDebugMode = false

-- **************** 由 HelperTool_mui 工具生成 ****************
-- 若前半段代码有改动，请修改HelperTool_mui目录下的Settings/HelperHeader.lua文件
-- 若后半段代码有改动，请修改HelperTool_mui目录下的Settings/HelperTail.lua文件

local TEACH_STATE = {
    NOT_START = 1,  --未开始
    LIVE = 2,       --运行中
    COMPLETE = 3,   --已完成
}

local NOTIFY_NODE_EMPTY = "[Teach] 动态控件设置失败，目标控件为空"

TeachEvent.tTeachingList = TeachEvent.tTeachingList or {}

function TeachEvent.Init()
    LOG.INFO("[Teach] Init")
    TeachEvent.RegEvent()
    TeachEvent.InitTeachNodeTab()
end

function TeachEvent.UnInit()
    LOG.INFO("[Teach] UnInit")
    TeachEvent.ClearAllTeach()
    Event.UnRegAll(TeachEvent)
    Timer.DelAllTimer(TeachEvent)
end

--重载
function TeachEvent.Reload(bClear)
    LOG.INFO("[Teach] Reload")
    if bClear then
        TeachEvent.UnInit()
        ReloadScript.Reload("Lua/Logic/Teach/TeachEvent.lua")
        ReloadScript.Reload("Lua/Logic/Teach/TeachEventStr.lua")
        TeachEvent.Init()
    else
        Event.UnRegAll(TeachEvent)
        Timer.DelAllTimer(TeachEvent)
        ReloadScript.Reload("Lua/Logic/Teach/TeachEvent.lua")
        ReloadScript.Reload("Lua/Logic/Teach/TeachEventStr.lua")
        TeachEvent.RegEvent()
    end

    if not GameSettingData.GetGameSetting(SettingCategory.Display, DISPLAY.OTHER_VISUAL, "显示教学") then
        TeachEvent.bEnabled = false
    end
end

function TeachEvent.InitTeachNodeTab()
    local tTeachNodeTab = {}
    for _, tLine in pairs(UITeachNodeTab) do
        if tLine.bEnable then
            local szNodePath = tLine.szNodePath
            local szBindUuid = tLine.szBindUuid
            if not string.is_nil(szNodePath) and not string.is_nil(szBindUuid) and not tTeachNodeTab[szNodePath] then
                tTeachNodeTab[szNodePath] = szBindUuid
            elseif tTeachNodeTab[szNodePath] ~= szBindUuid then
                LOG.ERROR("[Teach] InitTeachNodeTab Error, szNodePath is already exist. %s", tostring(szNodePath))
            end
        end
    end
    TeachEvent.tTeachNodeTab = tTeachNodeTab
end

function TeachEvent.SyncServerStorage()
    LOG.INFO("[Teach] SyncServerStorage")
    local tTeachState = {}
    local tVariable = {}

    for nTeachID, nServerIndex in pairs(TeachEvent.tTeachIDArray) do
        local bRet = Storage_Server.GetData("TeachState", nServerIndex)
        tTeachState[nTeachID] = bRet and TEACH_STATE.COMPLETE or TEACH_STATE.NOT_START
    end
    for szVariableKey, nServerIndex in pairs(TeachEvent.tVariableArray) do
        local bRet = Storage_Server.GetData("TeachVariable", nServerIndex)
        tVariable[szVariableKey] = bRet
    end

    Storage.Teach.tTeachState = tTeachState
    Storage.Teach.tVariable = tVariable
    Storage.Teach.Flush()
end

function TeachEvent.TeachStart(nTeachID, ...)
    if not nTeachID then return end
    --if Config.bOptickLuaSample then BeginSample("TeachEvent.TeachStart." .. tostring(nTeachID)) end

    local tTeachData = TeachEvent.tTeachDataList[nTeachID]
    local fnTeachAction = tTeachData and tTeachData.fnAction
    if fnTeachAction then
        LOG.INFO("[Teach] TeachStart: %s", nTeachID)
        local tTeaching = TeachEvent.tTeachingList[nTeachID]
        if tTeaching then
            Event.UnRegAll(tTeaching)
            Timer.DelAllTimer(tTeaching)
        end

        TeachEvent.tTeachingList[nTeachID] = {
            className = "TeachingList_" .. nTeachID,
            szAction = "Ready",
            bViewOpen = false,
            bWaitView = tTeaching and tTeaching.bWaitView or false,
            scriptView = tTeaching and tTeaching.scriptView or nil,
            config = nil,
        }
        TeachEvent.SetTeachState(nTeachID, TEACH_STATE.LIVE)
        fnTeachAction(nTeachID, ...)
        Event.Dispatch(EventType.OnTeachStart, nTeachID)
    end
    --if Config.bOptickLuaSample then EndSample() end
end

function TeachEvent.CheckCondition(nTeachID, ...)
    if not nTeachID then return end
    if not GetClientPlayer() then return end
    --if Config.bOptickLuaSample then BeginSample("TeachEvent.CheckCondition." .. tostring(nTeachID)) end

    local bResult = false
    local tTeachData = TeachEvent.tTeachDataList[nTeachID]
    if tTeachData then
        if not TeachEvent.bEnabled and not tTeachData.bIgnoreDisable then
            --if Config.bOptickLuaSample then EndSample() end
            return
        end

        bResult = tTeachData.fnCondition and tTeachData.fnCondition(nTeachID, ...)
        --LOG.INFO("[Teach] CheckCondition: %s - %s", nTeachID, tostring(bResult))

        --打印用记录
        if tTeachData.tCondition then
            tTeachData.nLastCheckTime = GetCurrentTime()
            for _, tLine in ipairs(tTeachData.tCondition) do
                tLine.bResult = tLine.fnExpression and tLine.fnExpression(nTeachID, ...)
            end
        end

        if TeachEvent.nMonitorTeachID == nTeachID then
            TeachEvent.PrintConditionCheckResult(nTeachID)
        end
    end
    --if Config.bOptickLuaSample then EndSample() end
    return bResult
end

function TeachEvent.TeachAction(nTeachID, szAction)
    if not nTeachID then return end

    szAction = szAction or "Empty"
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if tTeaching then
        tTeaching.szAction = szAction
        LOG.INFO("[Teach] TeachAction: %s - %s", nTeachID, szAction)

        Event.Dispatch(EventType.OnTeachAction, nTeachID)
    end
end

function TeachEvent.TeachComplete(nTeachID)
    if not nTeachID then return end

    LOG.INFO("[Teach] TeachComplete: %s", nTeachID)

    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    Event.UnRegAll(tTeaching)
    Timer.DelAllTimer(tTeaching)
    TeachEvent.tTeachingList[nTeachID] = nil

    TeachEvent.SetTeachState(nTeachID, TEACH_STATE.COMPLETE)
    Event.Dispatch(EventType.OnTeachComplete, nTeachID)

    local tTeachData = TeachEvent.tTeachDataList[nTeachID]
    if tTeachData and not tTeachData.bIgnoreAchievement then
        LOG.INFO("[Teach] ON_OUT_PUT_COMMENT %s", nTeachID)
        Event.Dispatch("ON_OUT_PUT_COMMENT") --触发教学成就计数
    end
end

function TeachEvent.TeachClose(nTeachID)
    if not nTeachID then return end

    TeachEvent.CloseTeachView(nTeachID)
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if tTeaching then
        if TeachEvent.bDebugMode then
            LOG.INFO("[Teach] TeachClose: %s\n%s", nTeachID, debug.traceback())
        else
            LOG.INFO("[Teach] TeachClose: %s", nTeachID)
        end
        Event.UnRegAll(tTeaching)
        Timer.DelAllTimer(tTeaching)
        TeachEvent.tTeachingList[nTeachID] = nil
    end

    if TeachEvent.GetTeachState(nTeachID) ~= TEACH_STATE.COMPLETE then
        TeachEvent.SetTeachState(nTeachID, TEACH_STATE.NOT_START)
        Event.Dispatch(EventType.OnTeachClose, nTeachID)
    end
end

--教学界面管理相关：

function TeachEvent.OpenTeachView(nTeachID, config)
    if not nTeachID then return end
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if not tTeaching then return end

    tTeaching.config = config
    tTeaching.bViewOpen = true
    TeachEvent.UpdateTeachView(nTeachID)
    Event.Dispatch(EventType.OnOpenTeachView, nTeachID)
end

function TeachEvent.CloseTeachView(nTeachID)
    if not nTeachID then return end

    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if tTeaching then
        tTeaching.bViewOpen = false
        TeachEvent.UpdateTeachView(nTeachID)
    end
    Event.Dispatch(EventType.OnCloseTeachView, nTeachID)
end

function TeachEvent.CloseAllTeachView()
    LOG.INFO("[Teach] CloseAllTeachView")
    for nTeachID, _ in pairs(TeachEvent.tTeachingList) do
        TeachEvent.CloseTeachView(nTeachID)
    end
    Event.Dispatch(EventType.OnCloseTeachView, nil)
end

function TeachEvent.UpdateTeachViewConfig(nTeachID, config)
    if not nTeachID then return end
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if not tTeaching then return end

    LOG.INFO("[Teach] UpdateTeachViewConfig: %s", nTeachID)
    tTeaching.config = config
    if tTeaching.scriptView then
        tTeaching.scriptView:OnEnter(nTeachID)
    end
end

function TeachEvent.GetTeachingConfig(nTeachID)
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    return tTeaching and tTeaching.config
end

function TeachEvent.UpdateTeachView(nTeachID)
    if not nTeachID then return end
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if not tTeaching then return end
    if tTeaching.bWaitView then return end

    if not tTeaching.scriptView and tTeaching.bViewOpen then
        local nViewID = VIEW_ID.PanelTeach
        local szNodePath = tTeaching.config and (tTeaching.config.szClickNodePath or UIHelper.GetNodePath(tTeaching.config.clickNode))
        if not string.is_nil(szNodePath) then
            if string.find(szNodePath, UILayer.Main) then
                nViewID = VIEW_ID.PanelTeach_UIMainLayer
            elseif string.find(szNodePath, UILayer.Page) then
                nViewID = VIEW_ID.PanelTeach_UIPageLayer
            elseif string.find(szNodePath, UILayer.Popup) then
                nViewID = VIEW_ID.PanelTeach_UIPopupLayer
            elseif string.find(szNodePath, UILayer.MessageBox) then
                nViewID = VIEW_ID.PanelTeach_UIMessageBoxLayer
            elseif string.find(szNodePath, UILayer.HoverTips) then
                nViewID = VIEW_ID.PanelTeach_UIHoverTipsLayer
            end
        end
        LOG.INFO("[Teach] OpenTeachView: %s", nTeachID)
        UIMgr.Open(nViewID, nTeachID)
    elseif tTeaching.scriptView and tTeaching.bViewOpen then
        LOG.INFO("[Teach] UpdateTeachView: %s", nTeachID)
        tTeaching.scriptView:OnEnter(nTeachID)
    elseif tTeaching.scriptView and not tTeaching.bViewOpen then
        LOG.INFO("[Teach] CloseTeachView: %s", nTeachID)
        UIMgr.Close(tTeaching.scriptView)
    end
end

function TeachEvent.OnTeachViewOpen(scriptView)
    local nTeachID = scriptView and scriptView.nTeachID
    if not nTeachID then return end
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if not tTeaching then return end

    LOG.INFO("[Teach] OnTeachViewOpen: %s", nTeachID)
    if tTeaching.scriptView then
        UIMgr.Close(tTeaching.scriptView)
    end

    tTeaching.scriptView = scriptView
    tTeaching.bWaitView = false
    TeachEvent.UpdateTeachView(nTeachID)
end

function TeachEvent.OnTeachViewClose(scriptView)
    local nTeachID = scriptView and scriptView.nTeachID
    if not nTeachID then return end
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    if not tTeaching then return end
    if tTeaching.scriptView ~= scriptView then return end

    LOG.INFO("[Teach] OnTeachViewClose: %s", nTeachID)
    tTeaching.scriptView = nil
    tTeaching.bWaitView = false
    TeachEvent.UpdateTeachView(nTeachID)
end

--关闭绑定在同一节点/界面/层级的教学
function TeachEvent.CloseTeachByViewBindInfo(nCurTeachID, szBindInfo)
    if not nCurTeachID then return end
    if not szBindInfo then return end
    LOG.INFO("[Teach] CloseTeachByViewBindInfo: %s", szBindInfo)

    local tTeachIDList = {}
    for nTeachID, tTeaching in pairs(TeachEvent.tTeachingList) do
        if nCurTeachID ~= nTeachID and tTeaching.scriptView then
            local szBindLayer, szBindPanel, szBindNode = tTeaching.scriptView:GetBindInfo()
            if szBindLayer == szBindInfo or szBindPanel == szBindInfo or szBindNode == szBindInfo then
                table.insert(tTeachIDList, nTeachID)
            end
        end
    end
    for _, nTeachID in pairs(tTeachIDList) do
        TeachEvent.TeachClose(nTeachID)
    end
end

--测试用打印信息：

function TeachEvent.GetTeachData(nTeachID)
    return TeachEvent.tTeachDataList[nTeachID]
end

function TeachEvent.GetTeachingAction(nTeachID)
    local tTeaching = TeachEvent.tTeachingList[nTeachID]
    return tTeaching and tTeaching.szAction
end

function TeachEvent.PrintConditionCheckResult(nTeachID)
    if not nTeachID then return end
    
    local szInfo = ""
    local tTeachData = TeachEvent.tTeachDataList[nTeachID]
    if tTeachData and tTeachData.tCondition then
        if tTeachData.nLastCheckTime then
            local nTime = (GetCurrentTime() - tTeachData.nLastCheckTime)
            szInfo = szInfo .. "教学 [#" .. nTeachID .. ": " .. tTeachData.szName .. "] 上次触发条件检测记录信息：\n"
            szInfo = szInfo .. "上次检测时间距当前 " .. nTime .. " 秒，\n"
            szInfo = szInfo .. "条件检测结果：\n"
            for _, tLine in ipairs(tTeachData.tCondition) do
                szInfo = szInfo .. tLine.szConditionName .. ": 【" .. tostring(tLine.bResult) .. "】\n"
            end
        else
            szInfo = "该教学暂未触发过条件检测"
        end
    end
    LOG.INFO("[Teach] " .. szInfo)
end

function TeachEvent.PrintTeachingInfoStr()
    LOG.INFO("[Teach]")
    for nTeachID, tTeaching in pairs(TeachEvent.tTeachingList or {}) do
        local szTeachName = TeachEvent.tTeachDataList[nTeachID].szName
        print("#" .. nTeachID .. ": " .. szTeachName .. " - " .. (tTeaching.szAction or ""))
    end
end

function TeachEvent.PrintTeachStateInfoStr(bIgnoreNotStart)
    LOG.INFO("[Teach]")
    for nTeachID, nTeachState in pairs(Storage.Teach.tTeachState or {}) do
        if TeachEvent.tTeachDataList[nTeachID] and (not bIgnoreNotStart or nTeachState ~= TEACH_STATE.NOT_START) then
            local szTeachName = TeachEvent.tTeachDataList[nTeachID].szName
            local _, szTeachState = table.contain_value(TEACH_STATE, nTeachState)
            print("#" .. nTeachID .. ": " .. szTeachName .. " - " .. (szTeachState or TEACH_STATE.NOT_START))
        end
    end
end

--监测教学条件检测情况
function TeachEvent.SetMonitorTeachConditionCheck(nTeachID)
    TeachEvent.nMonitorTeachID = nTeachID
end

function TeachEvent.ClearAllTeach()
    TeachEvent.CloseAllTeachView()
    for nTeachID, tTeaching in pairs(TeachEvent.tTeachingList or {}) do
        Event.UnRegAll(tTeaching)
        Timer.DelAllTimer(tTeaching)
    end
    TeachEvent.tTeachingList = {}
end

function TeachEvent.CloseAllTeach()
    TeachEvent.CloseAllTeachView()
    local tTeachIDList = {}
    for nTeachID, _ in pairs(TeachEvent.tTeachingList) do
        table.insert(tTeachIDList, nTeachID)
    end
    for _, nTeachID in pairs(tTeachIDList) do
        TeachEvent.TeachClose(nTeachID)
    end
end

--教学状态保存相关
function TeachEvent.GetTeachState(nTeachID)
    return Storage.Teach.tTeachState[nTeachID] or TEACH_STATE.NOT_START
end

function TeachEvent.SetTeachState(nTeachID, nTeachState)
    if not nTeachID then return end
    Storage.Teach.tTeachState[nTeachID] = nTeachState
    Storage.Teach.Flush()

    local nServerIndex = TeachEvent.tTeachIDArray[nTeachID]
    if not nServerIndex then return end

    local bRet = Storage_Server.GetData("TeachState", nServerIndex)
    local bValue = nTeachState == TEACH_STATE.COMPLETE
    if bRet ~= bValue then
        Storage_Server.SetData("TeachState", nServerIndex, bValue)
    end
end

function TeachEvent.ClearTeachState(nTeachID)
    TeachEvent.SetTeachState(nTeachID, nil)
end

function TeachEvent.ClearAllTeachState()
    Storage.Teach.tTeachState = {}
    Storage.Teach.Flush()

    for nTeachID, nServerIndex in pairs(TeachEvent.tTeachIDArray) do
        Storage_Server.SetData("TeachState", nServerIndex, false)
    end
end

--部分ActionDefine中调用的接口：

function TeachEvent.IsTeachNotStart(...)
    local tbTeachID = {...}
    for _, nTeachID in pairs(tbTeachID) do
        if TeachEvent.GetTeachState(nTeachID) ~= TEACH_STATE.NOT_START then
            return false
        end
    end
    return true
end

function TeachEvent.IsTeachLive(...)
    local tbTeachID = {...}
    for _, nTeachID in pairs(tbTeachID) do
        if TeachEvent.GetTeachState(nTeachID) == TEACH_STATE.LIVE then
            return true
        end
    end
    return false
end

function TeachEvent.IsTeachComplete(...)
    local tbTeachID = {...}
    for _, nTeachID in pairs(tbTeachID) do
        if TeachEvent.GetTeachState(nTeachID) ~= TEACH_STATE.COMPLETE then
            return false
        end
    end
    return true
end

function TeachEvent.HasLiveTeach(...)
    local tbIgnoreTeachID = {...} --排除的ID
    for nTeachID, tTeaching in pairs(TeachEvent.tTeachingList or {}) do
        if not table.contain_value(tbIgnoreTeachID, nTeachID) then
            return true
        end
    end
    return false
end

function TeachEvent.RegTeachEvent(nTeachID, szEventType, fnCallback, bOneShot, bNextFrame)
    if not nTeachID then return end
    if bNextFrame then
        --下一帧再注册事件，避免事件触发时注册的事件被立即触发
        Timer.AddFrame(TeachEvent.tTeachingList[nTeachID], 1, function()
            Event.Reg(TeachEvent.tTeachingList[nTeachID], szEventType, fnCallback, bOneShot)
        end)
    else
        Event.Reg(TeachEvent.tTeachingList[nTeachID], szEventType, fnCallback, bOneShot)
    end
end

function TeachEvent.UnRegTeachEvent(nTeachID, szEventType)
    if not nTeachID then return end
    Event.UnReg(TeachEvent.tTeachingList[nTeachID], szEventType)
end

function TeachEvent.AddTeachTimer(nTeachID, nTime, fnCallback)
    if not nTeachID then return end
    return Timer.Add(TeachEvent.tTeachingList[nTeachID], nTime, fnCallback)
end

function TeachEvent.AddTeachCycleTimer(nTeachID, nTime, fnCallback)
    if not nTeachID then return end
    return Timer.AddCycle(TeachEvent.tTeachingList[nTeachID], nTime, fnCallback)
end

function TeachEvent.DelTeachTimer(nTeachID, nTimerID)
    if not nTeachID then return end
    if not nTimerID then return end
    return Timer.DelTimer(TeachEvent.tTeachingList[nTeachID], nTimerID)
end

--- @param szNodePath szNodePath/szBindUuid/node
function TeachEvent.GetTeachBindNode(szNodePath)
    if not IsString(szNodePath) then
        return szNodePath
    end

    local szBindUuid = TeachEvent.tTeachNodeTab[szNodePath] or szNodePath
    local node = SceneMgr.GetPersistentNode(szBindUuid)
    if not node then
        node = UIHelper.GetChildByPath(UIMgr.GetCurrentScene(), szNodePath)
    end
    return node
end

function TeachEvent.WaitTargetNodeShow(nTeachID, szNodePath, fnCallback)
    if not nTeachID then return end
    local nTimerID
    nTimerID = Timer.AddFrameCycle(TeachEvent.tTeachingList[nTeachID], 1, function()
        local node = TeachEvent.GetTeachBindNode(szNodePath)
        if node and UIHelper.GetHierarchyVisible(node) then
            Timer.DelTimer(TeachEvent.tTeachingList[nTeachID], nTimerID)
            if fnCallback then
                fnCallback()
            end
        end
    end)
end

function TeachEvent.GetVariable(szKey)
    if not szKey then return end
    return Storage.Teach.tVariable[szKey]
end

function TeachEvent.SetVariable(szKey, bValue)
    if not szKey then return end

    Storage.Teach.tVariable[szKey] = bValue
    Storage.Teach.Flush()

    local nServerIndex = TeachEvent.tVariableArray[szKey]
    if not nServerIndex then return end

    bValue = not not bValue --to boolean
    local bRet = Storage_Server.GetData("TeachVariable", nServerIndex)
    if bRet ~= bValue then
        Storage_Server.SetData("TeachVariable", nServerIndex, bValue)
    end
end

function TeachEvent.ClearVariable(szKey)
    TeachEvent.SetVariable(szKey, nil)
end

function TeachEvent.ClearAllVariable()
    Storage.Teach.tVariable = {}
    Storage.Teach.Flush()

    for szVariableKey, nServerIndex in pairs(TeachEvent.tVariableArray) do
        Storage_Server.SetData("TeachVariable", nServerIndex, false)
    end
end

function TeachEvent.CallToServer(...)
    RemoteCallToServer(...)
end

--是否GM界面，当触发界面打开事件时，跳过GM界面
function TeachEvent.IsDebugView(nViewID)
    if nViewID == VIEW_ID.PanelNodeExplorer then
        return true
    end

    local szLayer = UIMgr.GetViewLayerByViewID(nViewID)
    if szLayer == UILayer.Debug then
        return true
    end

    return false
end

function TeachEvent.IsTeachView(nViewID)
    return table.contain_value(IGNORE_TEACH_VIEW_IDS, nViewID)
end

