TeachEvent.tTeachDataList[1] = {
    nTeachID = 1,
    szName = "操作模式选择界面弹出",
    bIgnoreDisable = false,
    bIgnoreAchievement = false,
    fnCondition = function(nTeachID) return ((not TeachEvent.IsTeachComplete(nTeachID)) and true) end,
    fnAction = function(nTeachID)
        local config = {}
        local fnCallback = function()
            TeachEvent.RegTeachEvent(nTeachID, EventType.OnViewOpen, function(nViewID)
                if nViewID == VIEW_ID.PanelMainCity then
                    local viewScript = UIMgr.GetViewScript(nViewID)
                    if viewScript and viewScript.nTeachID == nTeachID then
                        TeachEvent.UnRegTeachEvent(nTeachID, EventType.OnViewOpen)
                        TeachEvent.UnRegTeachEvent(nTeachID, EventType.OnViewClose)
                    end
                end
            end)
            TeachEvent.RegTeachEvent(nTeachID, EventType.OnViewClose, function(nViewID)
                if nViewID == VIEW_ID.PanelMainCity then
                    TeachEvent.TeachClose(nTeachID)
                end
            end)
            config.tbCoverView = config.tbCoverView or {}
            table.insert(config.tbCoverView, VIEW_ID.PanelHotSpotBanner)
            UIMgr.Open(VIEW_ID.PanelHintSelectMode)
            TeachEvent.CloseTeachView(nTeachID)
            TeachEvent.OpenTeachView(nTeachID, config)
            local fnCallback = function()
                TeachEvent.UnRegTeachEvent(nTeachID, EventType.OnViewClose)
                TeachEvent.TeachComplete(nTeachID) return
                
            end
            if not UIMgr.IsViewOpened(VIEW_ID.PanelHintSelectMode) then
                fnCallback()
            else
                TeachEvent.RegTeachEvent(nTeachID, EventType.OnViewClose, function(nViewID)
                    if nViewID == VIEW_ID.PanelHintSelectMode then
                        fnCallback()
                    end
                end)
            end
        end
        if UIMgr.IsViewOpened(VIEW_ID.PanelMainCity) then
            fnCallback()
        else
            TeachEvent.RegTeachEvent(nTeachID, EventType.OnViewOpen, function(nViewID)
                if nViewID == VIEW_ID.PanelMainCity then
                    fnCallback()
                end
            end)
        end
    end,
}

