    szName = "中地图·门派任务·段氏交通点",
    bIgnoreDisable = false,
    bIgnoreAchievement = false,
    fnCondition = function(nTeachID, nViewID) return ((QuestData.IsProgressing(27335) and nViewID == VIEW_ID.PanelMiddleMap and true and MapHelper.GetMapID() == 666 and (UIMgr.GetViewScript(VIEW_ID.PanelMiddleMap) and UIMgr.GetViewScript(VIEW_ID.PanelMiddleMap).bTraffic) == true) and true) end,
    fnAction = function(nTeachID, nViewID)
        local config = {}
        local btn
        local dwMapID, dwCityID = 666, 5147
        local scriptView = UIMgr.GetViewScript(VIEW_ID.PanelMiddleMap)
        for _, tbNodeScript in pairs(scriptView and scriptView.tbNodeScripts and scriptView.tbNodeScripts["Traffic"] or {}) do
            if scriptView.nMapID == dwMapID and tbNodeScript.tbInfo and tbNodeScript.tbInfo.dwCityID == dwCityID then
                btn = tbNodeScript.TogSign
                break
            end
        end
        local nodeArg = btn
        if IsString(nodeArg) then
            config.szClickNodePath = nodeArg
        else
            config.clickNode = nodeArg
            if not config.clickNode then
                LOG.ERROR(NOTIFY_NODE_EMPTY)
                TeachEvent.TeachClose(nTeachID)
                return
            end
        end
        local tbMask = {0, true, true}
        config.tbMaskData = {
            nLayerAlpha = tbMask[1],
            bEnableClickOther = tbMask[2],
            bDrawCycle = tbMask[3],
            nOffsetX = 0,
            nOffsetY = 0,
        }
        if not tbMask[2] then
            config.tbButtonData = config.tbButtonData or {}
        end
        local tbEffect = {PREFAB_ID.WidgetTeach_Highlight, nil, nil, true}
        config.tbEffectData = {
            nPrefabID = tbEffect[1],
            nScale = tbEffect[2],
            szSpriteName = tbEffect[3],
            bShowSfx = tbEffect[4],
        }
        config.tbTipsData = {
            szContent = g_tTotur.tMap.MiddleMap_MenPai_Transport.Text,
            nAlign = Align.Top,
            nOffsetX = 0,
            nOffsetY = 30,
        }
        local nGap = 30
        local tbAlign = {Align.Top, 0, nGap}
        config.tbTipsData.nAlign = tbAlign[1]
        config.tbTipsData.nOffsetX = tbAlign[2]
        config.tbTipsData.nOffsetY = tbAlign[3]
        TeachEvent.CloseTeachView(nTeachID)
        TeachEvent.OpenTeachView(nTeachID, config)
        TeachEvent.RegTeachEvent(nTeachID, EventType.OnTeachNodeClicked, function()
            TeachEvent.CloseTeachView(nTeachID)
            config = {}
            TeachEvent.TeachComplete(nTeachID) return
            
        end, true)
    end,
}

