            else
                config.clickNode = nodeArg
                if not config.clickNode then
                    LOG.ERROR(NOTIFY_NODE_EMPTY)
                    TeachEvent.TeachClose(nTeachID)
                    return
                end
            end
            local tbMask = {0, true, false}
            config.tbMaskData = {
                nLayerAlpha = tbMask[1],
                bEnableClickOther = tbMask[2],
                bDrawCycle = tbMask[3],
                nOffsetX = 0,
                nOffsetY = 0,
            }
            if not tbMask[2] then
                config.tbButtonData = config.tbButtonData or {}
            end
            local tbEffect = {PREFAB_ID.WidgetTeach_HighlightSquare, nil, nil, true}
            config.tbEffectData = {
                nPrefabID = tbEffect[1],
                nScale = tbEffect[2],
                szSpriteName = tbEffect[3],
                bShowSfx = tbEffect[4],
            }
            config.tbTipsData = {
                szContent = g_tTotur.tOperator.ShareToChat.Text,
                nAlign = Align.Top,
                nOffsetX = 0,
                nOffsetY = 30,
            }
            local nGap = 30
            local tbAlign = {Align.Right_Top, nGap, nGap}
            config.tbTipsData.nAlign = tbAlign[1]
            config.tbTipsData.nOffsetX = tbAlign[2]
            config.tbTipsData.nOffsetY = tbAlign[3]
            TeachEvent.CloseTeachView(nTeachID)
            TeachEvent.OpenTeachView(nTeachID, config)
            TeachEvent.RegTeachEvent(nTeachID, EventType.OnTeachAnyClicked, function()
                TeachEvent.SetVariable("Fourth_ShareToChat_done", true)
                TeachEvent.CloseTeachView(nTeachID)
                config = {}
                TeachEvent.TeachComplete(nTeachID) return
                
            end, true, true)
        end
        if UIMgr.IsViewOpened(VIEW_ID.PanelChatSocial) then
            fnCallback()
        else
            TeachEvent.RegTeachEvent(nTeachID, EventType.OnViewOpen, function(nViewID)
                if nViewID == VIEW_ID.PanelChatSocial then
                    fnCallback()
                end
            end)
        end
    end,
}

