function TeachEvent.RegEvent()
    Event.Reg(self, EventType.OnRoleLogin, function()
        --清理所有Live状态为未开始状态
        for nTeachID, nState in pairs(Storage.Teach.tTeachState) do
            if nState == TEACH_STATE.LIVE then
                Storage.Teach.tTeachState[nTeachID] = TEACH_STATE.NOT_START
                Storage.Teach.Flush()
            end
        end
    end)
    Event.Reg(self, EventType.OnClientPlayerLeave, function()
        TeachEvent.CloseAllTeach()
    end)
    Event.Reg(self, "SYNC_USER_PREFERENCES_END", function()
        --同步服务器存盘数据
        TeachEvent.SyncServerStorage()
    end)
    Event.Reg(self, EventType.OnSkipCurTeach, function()
        local tTeachIDList = {}
        for nTeachID, _ in pairs(TeachEvent.tTeachingList) do
            table.insert(tTeachIDList, nTeachID)
        end
        for _, nTeachID in pairs(tTeachIDList) do
            TeachEvent.TeachComplete(nTeachID)
        end
        TeachEvent.CloseAllTeachView()
    end)

    Event.Reg(self, "HELP_EVENT", function(szFun, arg1, arg2, arg3, arg4)
        if TeachEvent[szFun] then
            TeachEvent[szFun](arg1, arg2, arg3, arg4)
        end
    end)

    --服务器调用，教学开始事件
    Event.Reg(self, "TEACH_START_MUI", function(nTeachID, bCheckCondition, ...)
        if bCheckCondition then
            if TeachEvent.CheckCondition(nTeachID, ...) then
                TeachEvent.TeachStart(nTeachID)
            end
        else
            TeachEvent.TeachStart(nTeachID)
        end
    end)

    --服务器调用，教学完成事件
    Event.Reg(self, "TEACH_COMPLETE_MUI", function(nTeachID)
        TeachEvent.TeachComplete(nTeachID)
    end)

    --服务器调用，教学关闭事件
    Event.Reg(self, "TEACH_CLOSE_MUI", function(nTeachID)
        TeachEvent.TeachClose(nTeachID)
    end)

    Event.Reg(self, "QUEST_ACCEPTED", function(nQuestIndex, dwQuestID)
        if TeachEvent.OnAcceptQuest then
            TeachEvent.OnAcceptQuest(dwQuestID) --任务接受
        end
    end)
    Event.Reg(self, "SHARE_QUEST", function(nResultCode, dwQuestID, dwDestPlayerID)
        Timer.AddFrame(self, 1, function()
            if TeachEvent.OnAcceptQuest then
                TeachEvent.OnAcceptQuest(dwQuestID) --任务接受
            end
        end)
    end)
    Event.Reg(self, "QUEST_FINISHED", function(dwQuestID)
        if TeachEvent.OnFinishQuest then
            TeachEvent.OnFinishQuest(dwQuestID) --任务完成
        end
    end)
    Event.Reg(self, "QUEST_FAILED", function(nQuestIndex)
        if TeachEvent.OnQuestFailed then
            TeachEvent.OnQuestFailed() --任务失败
        end
    end)
    Event.Reg(self, "QUEST_CANCELED", function(dwQuestID)
        if TeachEvent.OnQuestCanceled then
            TeachEvent.OnQuestCanceled(dwQuestID) --任务放弃
        end
    end)
    Event.Reg(self, "PLAYER_LEVEL_UPDATE", function(dwID)
        local hPlayer = GetClientPlayer()
        if hPlayer and dwID == hPlayer.dwID then
            if TeachEvent.OnLevelUp then
                TeachEvent.OnLevelUp() --角色升级
            end
            if TeachEvent.OnCraftLevelUp then
                local tProfession = hPlayer.GetProfession()
                for key, tValue in pairs(tProfession) do
                    TeachEvent.OnCraftLevelUp(tValue.ProfessionID, tValue.Level, tValue.MaxLevel) --技艺升级
                end
            end
        end
    end)
    Event.Reg(self, "SKILL_UPDATE", function(dwID, dwLevel)
        if dwLevel > 1 then
            if TeachEvent.OnSkillLevelUp then
                TeachEvent.OnSkillLevelUp(dwID, dwLevel) --技能升级
            end
        elseif dwLevel == 1 then
            if TeachEvent.OnLearnSkill then
                TeachEvent.OnLearnSkill(dwID, dwLevel) --技能学习
            end
            if TeachEvent.OnLearnNeiGong then
                local hPlayer = GetClientPlayer()
                local tSkill = GetSkill(dwID, dwLevel)
                if hPlayer and hPlayer.dwForceID > 0 and tSkill and tSkill.nUIType == 2 and tSkill.dwBelongKungfu == 0 then
                    TeachEvent.OnLearnNeiGong() --学习到内功
                end
            end
        end
        if dwLevel == 2 then
            if TeachEvent.OnComprehendSkill then
                TeachEvent.OnComprehendSkill() --领悟招式
            end
        end
    end)
    Event.Reg(self, "UPDATE_REPUTATION", function()
        if TeachEvent.OnReputationUpdate then
            TeachEvent.OnReputationUpdate() --声望等级改变
        end
    end)
    -- Event.Reg(self, "UI_START_AUTOFLY", function()
    --     if TeachEvent.OnStartAutoFly then
    --         TeachEvent.OnStartAutoFly() --开始坐马车
    --     end
    -- end)
    -- Event.Reg(self, "UI_END_AUTOFLY", function()
    --     if TeachEvent.OnEndAutoFly then
    --         TeachEvent.OnEndAutoFly() --结束坐马车
    --     end
    -- end)
    -- Event.Reg(self, "UI_AUTOFLY_SWITCH_MAP", function()
    --     if TeachEvent.OnStartAutoChangeMap then
    --         TeachEvent.OnStartAutoChangeMap() --在马车上切换场景
    --     end
    -- end)
    Event.Reg(self, "SKILL_MOUNT_KUNG_FU", function(dwID, dwLevel)
        if TeachEvent.OnMountKungfu then
            local hPlayer = GetClientPlayer()
            if hPlayer and hPlayer.dwForceID > 0 then
                TeachEvent.OnMountKungfu(dwID, dwLevel) --装备内功
            end
        end
    end)
    Event.Reg(self, "EQUIP_ITEM_UPDATE", function(dwBox, dwX)
        if TeachEvent.OnEquipItemUpdate then
            local hPlayer = GetClientPlayer()
            if not hPlayer then
                return
            end
            local hItem = ItemData.GetPlayerItem(hPlayer, dwBox, dwX)
            if hItem then
                TeachEvent.OnEquipItemUpdate(hItem.dwID) --进行装备
            end
        end
    end)
    Event.Reg(self, "EQUIP_HORSE", function(dwBox, dwX)
        if TeachEvent.OnEquipItemUpdate then
            local hPlayer = GetClientPlayer()
            if not hPlayer then
                return
            end
            local hItem = ItemData.GetPlayerItem(hPlayer, dwBox, dwX)
            if hItem then
                TeachEvent.OnEquipItemUpdate(hItem.dwID) --进行装备
            end
        end
    end)
    Event.Reg(self, "LOADING_END", function()
        local hPlayer = GetClientPlayer()
        local hScene = hPlayer.GetScene()
        if hScene then
            if TeachEvent.OnEnterScene then
                TeachEvent.OnEnterScene(hScene.dwMapID) --场景切换
            end
        end
        if TeachEvent.OnEnterGame then
            TeachEvent.OnEnterGame() --进入游戏
        end
    end)
    Event.Reg(self, "PLAYER_FELLOWSHIP_CHANGE", function(nType)
        if TeachEvent.OnAddFriend then
            if nType == PLAYER_FELLOWSHIP_RESPOND.SUCCESS_ADD then
                TeachEvent.OnAddFriend() --加好友
            end
        end
    end)
    Event.Reg(self, "CHANGE_TONG_NOTIFY", function(nReason)
        if TeachEvent.OnTongChanged then
            TeachEvent.OnTongChanged(nReason) --帮会信息
        end
    end)
    -- Event.Reg(self, "EXECUTE_BINDING", function(szName, bDown)
    --     TeachEvent.OnExecuteBinding(szName, bDown) --执行快捷键的操作 TODO
    -- end)
    -- Event.Reg(self, "STOP_MOVIES", function(dwID)
    --     if TeachEvent.OnStopRLMovies then
    --         local hPlayer = GetClientPlayer()
    --         if not hPlayer then
    --             return
    --         end
    --         TeachEvent.OnStopRLMovies(dwID) --协议动画结束 2023.11.22改为OnURLMovieStop流媒体动画结束
    --     end
    -- end)
    Event.Reg(self, "CURRENCY_GET", function(szFun)
        if TeachEvent[szFun] then
            local bFirst = TeachEvent[szFun]()
            if bFirst then
                Event.Dispatch("CURRENCY_FIRST_GET", szFun)
            end
        end
    end)
    Event.Reg(self, EventType.OnPlayerSprintStateChanged, function(bSprintFlag)
        if TeachEvent.OnSprintStateChanged then
            TeachEvent.OnSprintStateChanged(bSprintFlag) --轻功状态改变
        end
    end)
    Event.Reg(self, "ADD_EXTERIOR", function(dwExteriorID)
        if TeachEvent.OnAddExterior then
            TeachEvent.OnAddExterior(dwExteriorID) --获得外装
        end
    end)
    Event.Reg(self, "ACQUIRE_FELLOW_PET", function(nFellowPetIndex)
        if TeachEvent.OnAddFellowPet then
            TeachEvent.OnAddFellowPet(nFellowPetIndex) --获得宠物
        end
    end)
    Event.Reg(self, "MAIL_LIST_UPDATE", function()
        if TeachEvent.OnAcceptMail then
            local nUnread, nTotal, nSysUnRead, nSysTotal = GetMailClient().CountMail()
            if nUnread and nUnread > 0 then
                TeachEvent.OnAcceptMail()
            end
        end
    end)
    Event.Reg(self, "ACQUIRE_DESIGNATION", function(nPrefix, nPostfix)
        if TeachEvent.OnAddDesignation then
            TeachEvent.OnAddDesignation(nPrefix, nPostfix, -1) --获得称号（前缀/后缀）
        end
    end)
    Event.Reg(self, "SET_GENERATION_NOTIFY", function(dwPlayerID, nGenerationIndex, nNameInForceIndex)
        local player = GetClientPlayer()
        if player and player.dwID == dwPlayerID then
            if TeachEvent.OnAddDesignation then
                TeachEvent.OnAddDesignation(-1, -1, nGenerationIndex) --获得称号（门派）
            end
        end
    end)
    --[[Event.Reg(self, "ON_CHANGE_NPC_EQUIP_NOTIFY", function(dwEquipID, nMethod)
        if nMethod == NPC_EQUIP_CHANGE_METHOD.ADD then
            if TeachEvent.OnAddNpcEquip then
                TeachEvent.OnAddNpcEquip(dwEquipID)
            end
        end
    end)]]
    Event.Reg(self, "NEW_ACHIEVEMENT", function(dwAchievementID)
        if TeachEvent.OnAddAchievement then
            TeachEvent.OnAddAchievement(dwAchievementID)
        end
    end)
    Event.Reg(self, EventType.OnCompassStateChanged, function()
        if TeachEvent.OnCompassStateChanged then
            TeachEvent.OnCompassStateChanged(g_bCompassVisible, g_bCompassStart, g_bCompassFind)
        end
    end)
    Event.Reg(self, "ON_ADD_PENDANT", function(dwPendantID)
        if dwPendantID then
            if TeachEvent.OnAddPendant then
                TeachEvent.OnAddPendant(dwPendantID)
            end
        end
    end)
    Event.Reg(self, EventType.OnTeachButtonClick, function(nViewID, szBtnName)
        if TeachEvent.OnTeachButtonClick then
            TeachEvent.OnTeachButtonClick(nViewID, szBtnName) --界面按钮点击
        end
    end)
    Event.Reg(self, EventType.OnTeachButtonShow, function(nViewID, szBtnName)
        if TeachEvent.OnTeachButtonShow then
            TeachEvent.OnTeachButtonShow(nViewID, szBtnName) --界面按钮出现
        end
    end)
    Event.Reg(self, EventType.OnViewOpen, function(nViewID)
        if TeachEvent.IsDebugView(nViewID) or TeachEvent.IsTeachView(nViewID) then
            return
        end
        if TeachEvent.OnViewOpen then
            TeachEvent.OnViewOpen(nViewID) --界面打开
        end
    end)
    Event.Reg(self, EventType.OnViewClose, function(nViewID)
        if TeachEvent.IsDebugView(nViewID) or TeachEvent.IsTeachView(nViewID) then
            return
        end
        if TeachEvent.OnViewClose then
            TeachEvent.OnViewClose(nViewID) --界面关闭
        end
    end)
    Event.Reg(self, EventType.OnGamepadTypeChanged, function(nGamepadType)
        if TeachEvent.OnGamepadTypeChanged then
            TeachEvent.OnGamepadTypeChanged(nGamepadType) --手柄状态改变
        end
    end)

    Event.Reg(self, EventType.OnTeachStart, function(nTeachID)
        if TeachEvent.OnTeachStart then
            TeachEvent.OnTeachStart(nTeachID) --教学开始
        end
    end)

    Event.Reg(self, EventType.OnTeachClose, function(nTeachID)
        if TeachEvent.OnTeachClose then
            TeachEvent.OnTeachClose(nTeachID) --教学关闭
        end
    end)

    Event.Reg(self, EventType.OnTeachComplete, function(nTeachID)
        if TeachEvent.OnTeachComplete then
            TeachEvent.OnTeachComplete(nTeachID) --教学完成
        end
    end)

    --测试模式下自动重载
    if TeachEvent.bDebugMode then
        Event.Reg(self, EventType.OnWindowsLostFocus, function()
            if not TeachEvent.szScriptMD5 then
                local szPath = "mui/Lua/Logic/Teach/TeachEvent.lua"
                local szScriptContent = Lib.GetStringFromFile(szPath)
                local szScriptMD5 = UIHelper.MD5(szScriptContent)
                TeachEvent.szScriptMD5 = szScriptMD5
            end
        end)

        Event.Reg(self, EventType.OnWindowsSetFocus, function()
            local szPath = "mui/Lua/Logic/Teach/TeachEvent.lua"
            local szScriptContent = Lib.GetStringFromFile(szPath)
            local szScriptMD5 = UIHelper.MD5(szScriptContent)

            --文件内容有修改时，触发重载
            if szScriptMD5 ~= TeachEvent.szScriptMD5 then
                LOG.INFO("[Teach] TeachEvent.lua Content Changed, Auto Reload; [MD5: %s] -> [MD5: %s]", tostring(TeachEvent.szScriptMD5), tostring(szScriptMD5))
                TeachEvent.Reload(true)
                TeachEvent.szScriptMD5 = szScriptMD5
            end
        end)
    end
end

